qry:select.qry:xquery:
for $r in table(' SELECT TTA10_LIQUIDACPROC.oi_tipohora, TTA01_TIPOHORAS.d_tipohora, totalhs = SUM(TTA10_LIQUIDACPROC.n_cantidadhs)
FROM TTA10_LIQUIDACPROC, TTA10_LIQUIDACJOR, TTA10_LIQUIDACPERS, TTA01_TIPOHORAS, PER02_PERSONAL_EMP, ORG02_ESTRUC_PERS
WHERE TTA10_LIQUIDACPROC.oi_liquidacjor = TTA10_LIQUIDACJOR.oi_liquidacjor AND PER02_PERSONAL_EMP.oi_personal_emp = TTA10_LIQUIDACPERS.oi_personal_emp AND PER02_PERSONAL_EMP.oi_personal_emp = ORG02_ESTRUC_PERS.oi_personal_emp AND TTA10_LIQUIDACPROC.oi_tipohora = TTA01_TIPOHORAS.oi_tipohora AND TTA10_LIQUIDACJOR.oi_liquidacionpers = TTA10_LIQUIDACPERS.oi_liquidacionpers AND TTA10_LIQUIDACPERS.oi_personal_emp = {#PARAM:@oi_personal_emp} AND ORG02_ESTRUC_PERS.oi_estructura={#PARAM:@oi_estructura} {%? (#FILTRO:@oi_estructura!='') {% AND ORG02_ESTRUC_PERS.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %} AND PER02_PERSONAL_EMP.oi_empresa = {%=#FILTRO:@oi_empresa%} {%? (#FILTRO:@f_des!='') {% AND TTA10_LIQUIDACPROC.f_fechoraentrada >= \'{%= #FILTRO:@f_des%}\'%} {% %} %} {%? (#FILTRO:@f_has!='') {% AND TTA10_LIQUIDACPROC.f_fechorasalida <= DATEADD(day,1,\'{%= #FILTRO:@f_has %}\') %} {% %} %}
GROUP BY TTA10_LIQUIDACPROC.oi_tipohora, TTA01_TIPOHORAS.d_tipohora ')/ROWS/ROW

